import { Routes } from '@angular/router';
import { authGuard } from './core/guards/auth.guard';
import { roleGuard } from './core/guards/role.guard';
import { FlowRoute } from './flow-meta';

// `data.flow` is the single source of truth for the user-flow graph AND the runtime navbar.
// Every navigable UI state is reachable by URL (hash routing). List filters live in
// `?status=` query params; create dialogs are dedicated `/new` routes.
export const routes: Routes = ([
  { path: '', redirectTo: 'dashboard', pathMatch: 'full' },

  {
    path: 'login',
    loadComponent: () => import('./pages/login/login.component').then((m) => m.LoginComponent),
    data: { flow: { flowId: 'login', node: 'login', entry: true, edgesTo: ['dashboard', 'signup'], label: 'Login' } },
  },
  {
    path: 'signup',
    loadComponent: () => import('./pages/signup/signup.component').then((m) => m.SignupComponent),
    data: { flow: { flowId: 'signup', node: 'signup', edgesTo: ['dashboard', 'login'], label: 'Sign up' } },
  },

  {
    path: '',
    loadComponent: () => import('./shared/layout.component').then((m) => m.LayoutComponent),
    canActivate: [authGuard],
    children: [
      {
        path: 'dashboard',
        loadComponent: () => import('./pages/dashboard/dashboard.component').then((m) => m.DashboardComponent),
        data: { flow: { flowId: 'dashboard', node: 'dashboard', showInNavbar: true, label: 'Dashboard', scope: 'all',
          edgesTo: ['customers', 'suppliers', 'products', 'purchase-orders', 'sales-orders', 'invoices', 'users', 'admin-settings'] } },
      },

      {
        path: 'customers',
        loadComponent: () => import('./pages/customers-list/customers-list.component').then((m) => m.CustomersListComponent),
        canActivate: [roleGuard], data: { roles: ['sales', 'admin'],
          flow: { flowId: 'customers', node: 'customers', showInNavbar: true, label: 'Customers', scope: 'sales', edgesTo: ['customer-new', 'customer-detail', 'dashboard'] } },
      },
      {
        path: 'customers/new',
        loadComponent: () => import('./pages/customer-new/customer-new.component').then((m) => m.CustomerNewComponent),
        canActivate: [roleGuard], data: { roles: ['sales', 'admin'],
          flow: { flowId: 'customer-new', node: 'customer-new', label: 'New customer', scope: 'sales', edgesTo: ['customers'] } },
      },
      {
        path: 'customers/:id',
        loadComponent: () => import('./pages/customer-detail/customer-detail.component').then((m) => m.CustomerDetailComponent),
        canActivate: [roleGuard], data: { roles: ['sales', 'admin'],
          flow: { flowId: 'customer-detail', node: 'customer-detail', label: 'Customer detail', scope: 'sales', edgesTo: ['customers', 'sales-orders'] } },
      },

      {
        path: 'suppliers',
        loadComponent: () => import('./pages/suppliers-list/suppliers-list.component').then((m) => m.SuppliersListComponent),
        canActivate: [roleGuard], data: { roles: ['purchasing', 'admin'],
          flow: { flowId: 'suppliers', node: 'suppliers', showInNavbar: true, label: 'Suppliers', scope: 'purchasing', edgesTo: ['supplier-detail', 'dashboard'] } },
      },
      {
        path: 'suppliers/:id',
        loadComponent: () => import('./pages/supplier-detail/supplier-detail.component').then((m) => m.SupplierDetailComponent),
        canActivate: [roleGuard], data: { roles: ['purchasing', 'admin'],
          flow: { flowId: 'supplier-detail', node: 'supplier-detail', label: 'Supplier detail', scope: 'purchasing', edgesTo: ['suppliers', 'purchase-orders'] } },
      },

      {
        path: 'products',
        loadComponent: () => import('./pages/products-list/products-list.component').then((m) => m.ProductsListComponent),
        data: { flow: { flowId: 'products', node: 'products', showInNavbar: true, label: 'Products', scope: 'all', edgesTo: ['product-detail', 'dashboard'] } },
      },
      {
        path: 'products/:id',
        loadComponent: () => import('./pages/product-form/product-form.component').then((m) => m.ProductFormComponent),
        data: { flow: { flowId: 'product-detail', node: 'product-detail', label: 'Product detail', scope: 'all', edgesTo: ['products'] } },
      },

      {
        path: 'purchase-orders',
        loadComponent: () => import('./pages/po-list/po-list.component').then((m) => m.PoListComponent),
        canActivate: [roleGuard], data: { roles: ['purchasing', 'admin'],
          flow: { flowId: 'purchase-orders', node: 'purchase-orders', showInNavbar: true, label: 'Purchase Orders', scope: 'purchasing', edgesTo: ['po-new', 'po-detail', 'dashboard'] } },
      },
      {
        path: 'purchase-orders/new',
        loadComponent: () => import('./pages/po-new/po-new.component').then((m) => m.PoNewComponent),
        canActivate: [roleGuard], data: { roles: ['purchasing', 'admin'],
          flow: { flowId: 'po-new', node: 'po-new', label: 'New purchase order', scope: 'purchasing', edgesTo: ['purchase-orders'] } },
      },
      {
        path: 'purchase-orders/:id',
        loadComponent: () => import('./pages/po-detail/po-detail.component').then((m) => m.PoDetailComponent),
        canActivate: [roleGuard], data: { roles: ['purchasing', 'admin'],
          flow: { flowId: 'po-detail', node: 'po-detail', label: 'Purchase order', scope: 'purchasing', edgesTo: ['purchase-orders', 'products'] } },
      },

      {
        path: 'sales-orders',
        loadComponent: () => import('./pages/so-list/so-list.component').then((m) => m.SoListComponent),
        canActivate: [roleGuard], data: { roles: ['sales', 'admin'],
          flow: { flowId: 'sales-orders', node: 'sales-orders', showInNavbar: true, label: 'Sales Orders', scope: 'sales', edgesTo: ['so-new', 'so-detail', 'dashboard'] } },
      },
      {
        path: 'sales-orders/new',
        loadComponent: () => import('./pages/so-new/so-new.component').then((m) => m.SoNewComponent),
        canActivate: [roleGuard], data: { roles: ['sales', 'admin'],
          flow: { flowId: 'so-new', node: 'so-new', label: 'New sales order', scope: 'sales', edgesTo: ['sales-orders'] } },
      },
      {
        path: 'sales-orders/:id',
        loadComponent: () => import('./pages/so-detail/so-detail.component').then((m) => m.SoDetailComponent),
        canActivate: [roleGuard], data: { roles: ['sales', 'admin'],
          flow: { flowId: 'so-detail', node: 'so-detail', label: 'Sales order', scope: 'sales', edgesTo: ['sales-orders', 'invoice-detail'] } },
      },

      {
        path: 'invoices',
        loadComponent: () => import('./pages/invoices-list/invoices-list.component').then((m) => m.InvoicesListComponent),
        canActivate: [roleGuard], data: { roles: ['sales', 'admin'],
          flow: { flowId: 'invoices', node: 'invoices', showInNavbar: true, label: 'Invoices', scope: 'sales', edgesTo: ['invoice-detail', 'dashboard'] } },
      },
      {
        path: 'invoices/:id',
        loadComponent: () => import('./pages/invoice-detail/invoice-detail.component').then((m) => m.InvoiceDetailComponent),
        canActivate: [roleGuard], data: { roles: ['sales', 'admin'],
          flow: { flowId: 'invoice-detail', node: 'invoice-detail', label: 'Invoice', scope: 'sales', edgesTo: ['invoices'] } },
      },

      {
        path: 'users',
        loadComponent: () => import('./pages/users/users.component').then((m) => m.UsersComponent),
        canActivate: [roleGuard], data: { roles: ['admin'],
          flow: { flowId: 'users', node: 'users', showInNavbar: true, label: 'Users', scope: 'admin', edgesTo: ['dashboard'] } },
      },
      {
        path: 'admin/settings',
        loadComponent: () => import('./pages/admin-settings/admin-settings.component').then((m) => m.AdminSettingsComponent),
        canActivate: [roleGuard], data: { roles: ['admin'],
          flow: { flowId: 'admin-settings', node: 'admin-settings', showInNavbar: true, label: 'Admin Settings', scope: 'admin', edgesTo: ['dashboard'] } },
      },
    ],
  },

  { path: '**', redirectTo: 'dashboard' },
] satisfies FlowRoute[]) as Routes;
